def clean_and_check_palindrome(s):
    # make it lowercase first
    s = s.lower()

    # loop and keep only letters and numbers
    cleaned = ""
    for char in s:
        if char.isalnum():
            cleaned = cleaned + char

    # check if it reads the same backwards
    reversed_str = cleaned[::-1]

    if cleaned == reversed_str:
        return True
    else:
        return False
